#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BS 16
#define AA(_i,_j) a[offset*size+_i*size+_j+offset]
#define BB(_i,_j) a[_i*size+_j]

__kernel void lud_diagonal(__global float* a, __local float* shared_mem, const int size, const int offset)
{
    int i, j, k;
    // shared_mem is unused here but reserved for compatibility with host code

    for (i = 0; i < BS; i++) {
        for (j = i; j < BS; j++) {
            for (k = 0; k < i; k++) {
                AA(i,j) = AA(i,j) - AA(i,k) * AA(k,j);
            }
        }

        float temp = 1.f / AA(i,i);
        for (j = i+1; j < BS; j++) {
            for (k = 0; k < i; k++) {
                AA(j,i) = AA(j,i) - AA(j,k) * AA(k,i);
            }
            AA(j,i) = AA(j,i) * temp;
        }
    }
}

__kernel void lud_perimeter(__global float* a, __local float* temp_top, __local float* temp_left, __local float* temp_diag, const int size, const int offset)
{
    int gid = get_global_id(0);
    int chunk_idx = gid;

    int size_inter = size - offset - BS;
    int chunks_in_inter_row = size_inter / BS;

    if (chunk_idx >= chunks_in_inter_row) return;

    int i, j, k;
    int i_global, j_global, i_here, j_here;
    float sum;

    // Copy block from a to temp_diag (temp)
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp_diag[i*BS + j] = a[size*(i + offset) + offset + j];
        }
    }

    i_global = offset;
    j_global = offset + BS * (chunk_idx + 1);

    // Update perimeter row blocks
    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            sum = 0.f;
            for (k = 0; k < i; k++) {
                sum += temp_diag[i*BS + k] * BB(i_global + k, j_global + j);
            }
            i_here = i_global + i;
            j_here = j_global + j;
            BB(i_here, j_here) = BB(i_here, j_here) - sum;
        }
    }

    j_global = offset;
    i_global = offset + BS * (chunk_idx + 1);

    // Update perimeter column blocks
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            sum = 0.f;
            for (k = 0; k < j; k++) {
                sum += BB(i_global + i, j_global + k) * temp_diag[k*BS + j];
            }
            i_here = i_global + i;
            j_here = j_global + j;
            a[size*i_here + j_here] = (a[size*i_here + j_here] - sum) / a[size*(offset + j) + offset + j];
        }
    }
}

__kernel void lud_internal(__global float* a, __local float* temp_top, __local float* temp_left, const int size, const int offset)
{
    int gid_x = get_global_id(0);
    int gid_y = get_global_id(1);

    int size_inter = size - offset - BS;
    int chunks_in_inter_row = size_inter / BS;

    if (gid_x >= chunks_in_inter_row || gid_y >= chunks_in_inter_row) return;

    int i, j, k, i_global, j_global;
    float sum[BS];
    for (i = 0; i < BS; i++) sum[i] = 0.f;

    i_global = offset + BS * (1 + gid_y);
    j_global = offset + BS * (1 + gid_x);

    // Load temp_top and temp_left blocks from global memory to local memory
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp_top[i*BS + j] = a[size*(i + offset) + j + j_global];
            temp_left[i*BS + j] = a[size*(i + i_global) + offset + j];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (i = 0; i < BS; i++) {
        for (k = 0; k < BS; k++) {
            float temp_left_val = temp_left[i*BS + k];
            for (j = 0; j < BS; j++) {
                sum[j] += temp_left_val * temp_top[k*BS + j];
            }
        }
        for (j = 0; j < BS; j++) {
            int idx_i = i + i_global;
            int idx_j = j + j_global;
            BB(idx_i, idx_j) -= sum[j];
            sum[j] = 0.f;
        }
    }
}
